import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def distance_metric(from_pos, to_pos):
        return np.linalg.norm(from_pos - to_pos)

    # Cooperative route planning
    cooperation_scores = {}
    for i, pos in enumerate(all_truck_pos):
        cooperation_scores[i] = {
            'position': pos,
            'distance': distance_metric(cur_truck_pos, pos),
            'available': True
        }

    # Evaluate each unvisited customer for suitability
    min_score = float('inf')
    best_node = None
    for idx, customer_pos in enumerate(unvisited_customers):
        dist = distance_metric(cur_truck_pos, customer_pos)
        time_to_reach = dist / truck_speed
        projected_arrival = current_time + time_to_reach
        window_start, window_end = time_windows[idx]

        # Skip if outside the time window
        if projected_arrival > window_end:
            continue

        # Factor in proximity to other trucks and coordination potential
        truck_compatibility = min(
            (distance_metric(other_truck['position'], customer_pos) / truck_speed + current_time) / 2
            for other_truck in cooperation_scores.values() if other_truck['available'])

        # Calculate the waiting time if arrived early
        waiting_time = max(0, window_start - projected_arrival)
        total_time_cost = time_to_reach + waiting_time
        score = total_time_cost + truck_compatibility

        # Decide based on optimized score
        if score < min_score:
            min_score = score
            best_node = idx

    return best_node
